esqlQuery.esql:
FROM metrics-generic.otel-default
| WHERE metrics.zookeeper.latency.max IS NOT NULL
// Average the peak-latency gauge readings per node across the time window
// latency.max reports the highest request latency since the last collection
| STATS avg_peak_latency = AVG(metrics.zookeeper.latency.max) BY host.name
// Threshold: sustained peak latency above 500 ms signals degradation
// Sustained high latency risks Kafka broker session timeouts
// Adjust based on your ensemble's baseline and SLA requirements
| WHERE avg_peak_latency > 500
